const toStr = (v) => String(v ?? '').trim();
const toNum = (v) => {
  const n = Number(v);
  return Number.isFinite(n) ? n : null;
};

const raw = $json || {};
const chatInput = toStr(raw.chatInput || raw.message || raw.text || raw.input || '');
if (!chatInput) {
  throw new Error('[Normalize Chat Input] mensagem vazia.');
}

const lower = chatInput.toLowerCase();
const isImpact = lower.startsWith('/impact') || lower.startsWith('impact:') || lower.startsWith('impact ');

const pick = (label) => {
  const re = new RegExp(label + '\s*[:=]\s*([^|\n]+)', 'i');
  const m = chatInput.match(re);
  return m ? toStr(m[1]) : '';
};

const analysisIdFromText = (() => {
  const m = chatInput.match(/analysis[_ ]?id\s*[:=]\s*(\d+)/i);
  return m ? toNum(m[1]) : null;
})();

const changeIdFromText = (() => {
  const m = chatInput.match(/change[_ ]?id\s*[:=]\s*(\d+)/i);
  return m ? toNum(m[1]) : null;
})();

const repoFromText = (() => {
  const m = chatInput.match(/repo\s*[:=]\s*([a-zA-Z0-9_\-]+)/i);
  return m ? toStr(m[1]) : '';
})();

return [{
  json: {
    action: isImpact ? 'impact_analysis' : 'ask',
    question: chatInput,
    analysis_id: analysisIdFromText,
    change_id: changeIdFromText,
    repo: repoFromText,

    impact_problem: pick('problema') || (isImpact ? chatInput.replace(/^\/impact\s*/i, '').replace(/^impact[: ]/i, '').trim() : ''),
    impact_expected_change: pick('mudanca') || pick('expected_change') || '',
    impact_evidence: pick('evidencias') || pick('evidence') || '',
    impact_constraints: pick('restricoes') || pick('constraints') || '',

    anthropic_api_key: toStr(
      ($env && $env.ANTHROPIC_API_KEY) ||
      (typeof process !== 'undefined' && process.env ? process.env.ANTHROPIC_API_KEY : '') ||
      ''
    ),
    llm_model: toStr(($env && $env.LLM_MODEL) || 'claude-sonnet-4-5-20250929'),
    max_tokens: 1200,
    impact_workflow_id: toStr(
      ($env && $env.IMPACT_WORKFLOW_ID) ||
      (typeof process !== 'undefined' && process.env ? process.env.IMPACT_WORKFLOW_ID : '') ||
      ''
    )
  }
}];

const toStr = (v) => String(v ?? '').trim();

if (!toStr($json.impact_workflow_id)) {
  throw new Error('[Prepare Impact Inputs] IMPACT_WORKFLOW_ID ausente no environment.');
}

return [{
  json: {
    impact_workflow_id: $json.impact_workflow_id,
    problema: $json.impact_problem || '',
    mudanca: $json.impact_expected_change || '',
    evidencias: $json.impact_evidence || '',
    restricoes: $json.impact_constraints || '',
    source_chat_message: $json.question || ''
  }
}];

return [{
  json: {
    output: [
      'Impact Analysis acionado com sucesso.',
      '',
      'Resumo do pedido:',
      '- problema: ' + String($json.problema || ''),
      '- mudanca: ' + String($json.mudanca || ''),
      '- evidencias: ' + String($json.evidencias || ''),
      '- restricoes: ' + String($json.restricoes || '')
    ].join('\n')
  }
}];

const getRows = (name) => {
  try {
    return $items(name, 0, 0).map((i) => i.json || {});
  } catch (_e) {
    return [];
  }
};

const req = (getRows('Normalize Chat Input')[0] || {});
const toStr = (v) => String(v ?? '').trim();
const toNum = (v) => {
  const n = Number(v);
  return Number.isFinite(n) ? n : null;
};
const norm = (v) => toStr(v)
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .toLowerCase();

const analysisRows = getRows('Load Impact Analysis');
const repoRows = getRows('Load Repos Table');
const changeRows = getRows('Load Changes In Repo');
const codeRows = getRows('Load Code Changes');
const testsuiteRows = getRows('Load Testsuites For Change');
const testRows = getRows('Load Tests For Testsuite');

if (analysisRows.length === 0) throw new Error('[Build Review Context] impact_analysis vazio.');
if (changeRows.length === 0) throw new Error('[Build Review Context] changes_in_repo vazio.');
if (codeRows.length === 0) throw new Error('[Build Review Context] code_changes vazio.');

const question = toStr(req.question || '');
if (!question) throw new Error('[Build Review Context] question vazia.');

const selectedAnalysisId = toNum(req.analysis_id) || Math.max(...analysisRows.map((r) => toNum(r.id)).filter((n) => Number.isFinite(n)));
if (!selectedAnalysisId) throw new Error('[Build Review Context] analysis_id nao resolvido.');

const analysisRow = analysisRows.find((r) => toNum(r.id) === selectedAnalysisId);
if (!analysisRow) throw new Error('[Build Review Context] analysis_id nao encontrado: ' + selectedAnalysisId);

const repoFilter = norm(req.repo || '');
const changeIdFilter = toNum(req.change_id);

const repoIdToName = new Map();
for (const r of repoRows) {
  const id = toNum(r.id);
  if (!id) continue;
  repoIdToName.set(id, toStr(r.repo_name || r.name || 'repo-' + id));
}

const testsBySuite = new Map();
for (const t of testRows) {
  const sid = toNum(t.testsuite_id);
  if (!sid) continue;
  if (!testsBySuite.has(sid)) testsBySuite.set(sid, []);
  const d = toStr(t.description || t.step || t.test_description);
  if (d) testsBySuite.get(sid).push(d);
}

const suitesByChange = new Map();
for (const s of testsuiteRows) {
  const sid = toNum(s.id || s.testsuite_id);
  const cid = toNum(s.change_id);
  if (!sid || !cid) continue;
  if (!suitesByChange.has(cid)) suitesByChange.set(cid, []);
  suitesByChange.get(cid).push(sid);
}

const codeByChange = new Map();
for (const c of codeRows) {
  const cid = toNum(c.change_id);
  if (!cid) continue;
  if (!codeByChange.has(cid)) codeByChange.set(cid, []);
  const block = toStr(c.code);
  if (block) codeByChange.get(cid).push(block);
}

const changes = [];
for (const ch of changeRows) {
  const cid = toNum(ch.id || ch.change_id);
  if (!cid) continue;

  const repoId = toNum(ch.repo_id);
  const repoName = toStr(ch.repo_name || repoIdToName.get(repoId) || 'repo-' + (repoId || 'na'));
  if (repoFilter && norm(repoName) !== repoFilter) continue;
  if (changeIdFilter && cid !== changeIdFilter) continue;

  const suiteIds = suitesByChange.get(cid) || [];
  const tests = suiteIds.flatMap((sid) => testsBySuite.get(sid) || []);

  changes.push({
    change_id: cid,
    repo_name: repoName,
    change_summary: toStr(ch.change_summary || ''),
    code_changes: (codeByChange.get(cid) || []).slice(0, 20),
    tests: tests.slice(0, 80)
  });
}

if (changes.length === 0) {
  throw new Error('[Build Review Context] nenhum change encontrado para os filtros informados.');
}

const payload = {
  analysis_id: selectedAnalysisId,
  question,
  analysis_summary: toStr(analysisRow.change_summary || ''),
  analysis_complexity: toStr(analysisRow.complexity_level || ''),
  filters: {
    repo: repoFilter || null,
    change_id: changeIdFilter || null
  },
  changes
};

return [{
  json: {
    analysis_id: selectedAnalysisId,
    question,
    review_context_text: JSON.stringify(payload, null, 2),
    anthropic_api_key: toStr(req.anthropic_api_key || ''),
    llm_model: toStr(req.llm_model || 'claude-sonnet-4-5-20250929'),
    max_tokens: 1200
  }
}];

const toStr = (v) => String(v ?? '').trim();
const toNum = (v) => {
  const n = Number(v);
  return Number.isFinite(n) ? n : null;
};

const extractText = (resp) => {
  const blocks = Array.isArray(resp?.content) ? resp.content : [];
  return blocks
    .filter((b) => b && b.type === 'text' && typeof b.text === 'string')
    .map((b) => b.text.trim())
    .filter(Boolean)
    .join('\n')
    .trim();
};

const tryParseJson = (raw) => {
  try { return JSON.parse(raw); } catch (_e) {}
  const s = raw.indexOf('{');
  const e = raw.lastIndexOf('}');
  if (s >= 0 && e > s) {
    try { return JSON.parse(raw.slice(s, e + 1)); } catch (_e) {}
  }
  return null;
};

const input = $json || {};
const question = toStr(input.question || '');
const contextText = toStr(input.review_context_text || '');
if (!question) throw new Error('[Answer Review Question] question vazia.');
if (!contextText) throw new Error('[Answer Review Question] review_context_text vazio.');

const envKey = (typeof process !== 'undefined' && process.env && process.env.ANTHROPIC_API_KEY)
  ? String(process.env.ANTHROPIC_API_KEY).trim()
  : '';
const apiKey = toStr(input.anthropic_api_key || envKey);
if (!apiKey) throw new Error('[Answer Review Question] ANTHROPIC_API_KEY ausente.');

const model = toStr(input.llm_model || 'claude-sonnet-4-5-20250929');
const maxTokens = toNum(input.max_tokens) || 1200;

const systemPrompt = [
  'Voce e revisor tecnico de changes do FastRoute.',
  'Responda SOMENTE JSON valido sem markdown.',
  'Use exclusivamente o contexto recebido.',
  'Formato:',
  '{',
  '  "resposta": "string",',
  '  "evidencias": ["string"],',
  '  "sugestao_correcao": "string"',
  '}'
].join('\n');

const userPrompt = ['Pergunta:', question, '', 'Contexto:', contextText].join('\n');

let resp;
try {
  resp = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.anthropic.com/v1/messages',
    headers: {
      'x-api-key': apiKey,
      'anthropic-version': '2023-06-01',
      'content-type': 'application/json'
    },
    body: {
      model,
      max_tokens: maxTokens,
      temperature: 0,
      system: systemPrompt,
      messages: [{ role: 'user', content: userPrompt }]
    },
    json: true
  });
} catch (e) {
  const detail = e?.response?.body ? JSON.stringify(e.response.body) : String(e?.message || e);
  throw new Error('[Answer Review Question] erro Anthropic: ' + detail);
}

const raw = extractText(resp);
if (!raw) throw new Error('[Answer Review Question] resposta vazia do modelo.');

const parsed = tryParseJson(raw);
if (!parsed || typeof parsed !== 'object') {
  throw new Error('[Answer Review Question] JSON invalido do modelo. raw=' + raw.slice(0, 1000));
}

return [{
  json: {
    output: [
      toStr(parsed.resposta || ''),
      '',
      'Evidencias:',
      ...(Array.isArray(parsed.evidencias) ? parsed.evidencias.map((e) => '- ' + String(e)) : []),
      '',
      'Sugestao de correcao:',
      toStr(parsed.sugestao_correcao || '(sem sugestao)'),
      '',
      '[meta] model=' + model + ' | analysis_id=' + String(input.analysis_id || '')
    ].join('\n')
  }
}];
